export function LoginCard({ children, style, ...props }: LoginCardProps) {
  const { theme } = useTheme();
  return (
    <View 
      style={[
        styles.card, 
        { backgroundColor: theme.cardBg || theme.background, borderColor: theme.cardBorder || theme.border }, 
        style
      ]} 
      {...props}
    >
      {children}
    </View>
  );
}

export interface LoginCardHeaderProps {
  title: string;
  description?: string;
  style?: StyleProp<ViewStyle>;
}

export function OtpInput({
  length = 4,
  label,
  description,
  error,
  size = "md",
  style,
  keyboardType = "number-pad",
  onChangeCode,
  onComplete,
  ...rest
}: Props) {
  const { theme } = useTheme()

  const safeLength: OtpLength = useMemo(() => {
    if (length === 6 || length === 8) return length
    return 4
  }, [length])

  const [values, setValues] = useState<string[]>(() =>
    Array.from({ length: safeLength }, () => "")
  )

export function Progress({ value = 0, style, indicatorStyle }: ProgressProps) {
  const { theme } = useTheme();

  // Clamp value between 0 and 100
  const clampedValue = Math.min(Math.max(value, 0), 100);

  return (
    <View style={[styles.track, { backgroundColor: theme.muted || 'rgba(255,255,255,0.15)' }, style]}>
      <View 
        style={[
          styles.indicator, 
          { 
            backgroundColor: theme.text || theme.primary || '#fff', 
            width: `${clampedValue}%` 
          }, 
          indicatorStyle
        ]} 
      />
    </View>
  );
}

