export function Skeleton({ style, isLoaded = false, children }: SkeletonProps) {
  const { theme } = useTheme();
  const opacity = useRef(new Animated.Value(0.4)).current;

  useEffect(() => {
    let animation: Animated.CompositeAnimation | null = null;

    if (!isLoaded) {
      animation = Animated.loop(
        Animated.sequence([
          Animated.timing(opacity, {
            toValue: 0.8,
            duration: 1000,
            useNativeDriver: true,
          }),
          Animated.timing(opacity, {
            toValue: 0.4,
            duration: 1000,
            useNativeDriver: true,
          }),
        ])
      );

export function Slider({
  min = 0,
  max = 100,
  step = 1,
  value = 0,
  onValueChange,
  startLabel,
  endLabel,
  trackColor = "#e2e8f0",
  rangeColor = "#0f172a",
  thumbColor = "#ffffff",
  disabled = false,
}: SliderProps) {
  const trackWidth = useSharedValue(0);
  const position = useSharedValue(
    ((value - min) / (max - min)) * (trackWidth.value || 1)
  );
  const lastPosition = useSharedValue(position.value);

  const clamp = (val: number, lo: number, hi: number) =>
    Math.min(Math.max(val, lo), hi);

export function useTheme() {
  const ctx = useContext(ThemeContext);
  if (!ctx) {
    throw new Error("useTheme must be used within ThemeProvider");
  }
  return ctx;
}

export function cn<T>(...styles: (T | false | null | undefined)[]) {
  return styles.filter(Boolean) as T[];
}
